Typewriter effect:
```js
typeText(label, fullText, charDelay) {
    let index = 0
    label.setString('')
    this.schedule(() => {
        index++
        label.setString(fullText.substring(0, index))
        if (index >= fullText.length) {
            this.unschedule(this._typeTimer)
        }
    }, charDelay, fullText.length - 1, 0, 'typewriter')
}
