        const local = sprite.convertTouchToNodeSpace(touch)
        return cc.rectContainsPoint(cc.rect(0,0,sprite.width,sprite.height), local)
    },
    onTouchMoved: (touch) => {
        const delta = touch.getDelta()
        sprite.x += delta.x
        sprite.y += delta.y
    }
}, this)
```

