```js
class GameLayer extends cc.Layer {
    onEnter() {
        super.onEnter()
        const size = cc.director.getWinSize()
        // Background
        const bg = new cc.Sprite('res/bg.png')
        bg.setPosition(size.width/2, size.height/2)
        this.addChild(bg, -1)
        // Hero
        this.hero = new cc.Sprite('res/hero.png')
        this.hero.setPosition(100, 200)
        this.addChild(this.hero, 1)
        // Input
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (touch) => { return true },
            onTouchMoved: (touch) => {
                const d = touch.getDelta()
                this.hero.x += d.x
                this.hero.y += d.y
            }
        }, this)
        this.scheduleUpdate()
    }
    update(dt) { /* game logic */ }
    onExit() {
        cc.eventManager.removeListener(this._listener)
        super.onExit()
    }
}
cc.director.runScene(new cc.Scene().addChild(new GameLayer()))
```

