Screen shake effect:
```js
shakeScreen(layer, intensity, duration) {
    const shakes = Math.floor(duration / 0.05)
    const actions = []
    for (let i = 0; i < shakes; i++) {
        const dx = (Math.random() - 0.5) * intensity
        const dy = (Math.random() - 0.5) * intensity
        actions.push(cc.moveTo(0.025, cc.p(dx, dy)))
    }
    actions.push(cc.moveTo(0.025, cc.p(0, 0)))  // reset
    layer.runAction(cc.sequence(actions))
}
